import re


def grep_search(regex_pattern, include_ext='.py', search_dir='.', case_sensitive=True, max_results=500):
    results = []
    for root, dirs, files in os.walk(search_dir):
        for file in files:
            if file.endswith(include_ext):
                file_path = os.path.join(root, file)
                with open(file_path, 'r', encoding='utf-8') as f:
                    lines = f.readlines()
                    for i, line in enumerate(lines):
                        if case_sensitive:
                            match = re.search(regex_pattern, line)
                        else:
                            match = re.search(regex_pattern, line, re.IGNORECASE)
                        if match:
                            results.append((file_path, i + 1, line.strip()))
                            if len(results) >= max_results:
                                break
                    if len(results) >= max_results:
                        break
        if len(results) >= max_results:
            break
    return results

